import{_ as a,o as i,c as d,S as t}from"./chunks/framework.C6RQlTYc.js";const m=JSON.parse('{"title":"Embedding（向量嵌入）","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_9-embedding.md","filePath":"直击概念/17ai/s_ai_9-embedding.md","lastUpdated":1778207238000}'),n={name:"直击概念/17ai/s_ai_9-embedding.md"};function l(r,e,s,o,h,b){return i(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="embedding-向量嵌入" tabindex="-1">Embedding（向量嵌入） <a class="header-anchor" href="#embedding-向量嵌入" aria-label="Permalink to &quot;Embedding（向量嵌入）&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>Embedding（向量嵌入）是将离散的对象（词、句子、图片等）映射到<strong>连续向量空间</strong>中的稠密向量表示。在这个空间中，语义相近的对象距离也相近。</p><p>简单理解：Embedding 就是给每个词/句子/文档分配一个<strong>高维坐标</strong>，语义相似的文本在这个空间中的坐标距离很近。</p><p><strong>示例</strong>：</p><ul><li>&quot;猫&quot; 的向量 ≈ [0.2, 0.8, -0.3, ...]</li><li>&quot;狗&quot; 的向量 ≈ [0.25, 0.75, -0.28, ...]（两者余弦相似度很高）</li><li>&quot;电脑&quot; 的向量 ≈ [-0.6, 0.1, 0.7, ...]（与前两者相似度低）</li></ul><h2 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h2><h3 id="word-embedding-词嵌入" tabindex="-1">Word Embedding（词嵌入） <a class="header-anchor" href="#word-embedding-词嵌入" aria-label="Permalink to &quot;Word Embedding（词嵌入）&quot;">​</a></h3><p>最早的 Embedding 形式，将单个词映射到向量：</p><ul><li><strong>Word2Vec</strong>（2013）：通过 CBOW 或 Skip-gram 训练</li><li><strong>GloVe</strong>（2014）：基于全局词共现矩阵</li><li><strong>FastText</strong>：将词分解为 n-gram 字符子串</li></ul><h3 id="sentence-embedding-句子嵌入" tabindex="-1">Sentence Embedding（句子嵌入） <a class="header-anchor" href="#sentence-embedding-句子嵌入" aria-label="Permalink to &quot;Sentence Embedding（句子嵌入）&quot;">​</a></h3><p>将整句话映射为单个向量：</p><ul><li><strong>BERT Embedding</strong>：取 [CLS] token 或各 token 平均</li><li><strong>Sentence-BERT</strong>：专门为句子相似度优化的 BERT</li><li><strong>OpenAI text-embedding-3</strong>：商用 Embedding 模型</li></ul><h3 id="向量运算" tabindex="-1">向量运算 <a class="header-anchor" href="#向量运算" aria-label="Permalink to &quot;向量运算&quot;">​</a></h3><p>Embedding 向量支持语义运算：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>king - man + woman ≈ queen</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这是 Embedding 的经典特性：向量空间中的方向和距离编码了语义关系。</p><h2 id="embedding-在前端的应用" tabindex="-1">Embedding 在前端的应用 <a class="header-anchor" href="#embedding-在前端的应用" aria-label="Permalink to &quot;Embedding 在前端的应用&quot;">​</a></h2><h3 id="语义搜索" tabindex="-1">语义搜索 <a class="header-anchor" href="#语义搜索" aria-label="Permalink to &quot;语义搜索&quot;">​</a></h3><ol><li>将用户查询转为 Embedding 向量</li><li>在向量数据库中搜索最相似的文档向量</li><li>返回语义相关的文档（而不是关键词匹配）</li></ol><h3 id="文本相似度" tabindex="-1">文本相似度 <a class="header-anchor" href="#文本相似度" aria-label="Permalink to &quot;文本相似度&quot;">​</a></h3><p>用<strong>余弦相似度</strong>计算两个 Embedding 向量的距离：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>cosine_similarity(A, B) = (A · B) / (||A|| · ||B||)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>值域 [-1, 1]，越接近 1 越相似。</p><h3 id="推荐系统" tabindex="-1">推荐系统 <a class="header-anchor" href="#推荐系统" aria-label="Permalink to &quot;推荐系统&quot;">​</a></h3><ul><li>将用户行为序列 Embedding</li><li>将物品描述 Embedding</li><li>匹配最相关的推荐内容</li></ul><h2 id="常用-embedding-模型" tabindex="-1">常用 Embedding 模型 <a class="header-anchor" href="#常用-embedding-模型" aria-label="Permalink to &quot;常用 Embedding 模型&quot;">​</a></h2><table><thead><tr><th>模型</th><th>维度</th><th>特点</th></tr></thead><tbody><tr><td>text-embedding-3-small</td><td>512/1536</td><td>OpenAI，性价比高</td></tr><tr><td>text-embedding-3-large</td><td>256/1024/3072</td><td>OpenAI，效果最好</td></tr><tr><td>bge-large-zh-v1.5</td><td>1024</td><td>中文 Embedding 标杆</td></tr><tr><td>m3e-large</td><td>1024</td><td>中文社区流行</td></tr><tr><td>all-MiniLM-L6-v2</td><td>384</td><td>轻量开源，适合浏览器</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>Embedding 和传统的关键词索引有什么区别？</li><li>如何判断两个 Embedding 向量的相似度？</li><li>前端可以做 Embedding 计算吗？为什么通常放在后端？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://developers.google.com/machine-learning/crash-course/embeddings" target="_blank" rel="noreferrer">Google Embedding 课程</a></li><li><a href="https://platform.openai.com/docs/guides/embeddings" target="_blank" rel="noreferrer">OpenAI Embeddings Guide</a></li></ul>',32)])])}const c=a(n,[["render",l]]);export{m as __pageData,c as default};
